type Interruptor<TArgs extends any[] = any[]> = (context: {
    request: Request;
    ctx: Record<string, any>;
    args: TArgs;
}) => Promise<Response | void> | Response | void;
type ServerFunction<TArgs extends any[] = any[], TResult = any> = (...args: TArgs) => Promise<TResult>;
type ServerFunctionOptions = {
    method?: "GET" | "POST";
};
type WrappedServerFunction<TArgs extends any[] = any[], TResult = any> = {
    (...args: TArgs): Promise<TResult>;
    method?: "GET" | "POST";
};
export type ServerFunctionWrap = (fn: Function, args: any[], type: "action" | "query") => Promise<any>;
/**
 * Register a wrapper that runs around every server action and query handler.
 *
 * Call this once in your worker entry point. The wrapper receives the main
 * handler function, its arguments, and the type ("action" or "query").
 * Interruptors run *outside* the wrapper.
 *
 * Only one wrapper is active at a time; the most recent call wins.
 *
 * @example
 * ```ts
 * import { registerServerFunctionWrap } from "rwsdk/worker";
 * import * as Sentry from "@sentry/cloudflare";
 *
 * registerServerFunctionWrap((fn, args, type) =>
 *   Sentry.startSpan(
 *     { name: fn.name, op: `function.rsc_${type}` },
 *     () => fn(...args)
 *   )
 * );
 * ```
 */
export declare function registerServerFunctionWrap(wrap: ServerFunctionWrap): void;
/**
 * @internal Reset the global wrap — only for tests.
 */
export declare function __resetServerFunctionWrap(): void;
/**
 * Wrap a function to be used as a server query.
 *
 * - **Method**: Defaults to `GET`. can be changed via `options`.
 * - **Behavior**: When called from the client, it returns data-only and does **not** rehydrate or re-render the React page.
 * - **Location**: Must be defined in a file with `"use server"`. We recommend `queries.ts` colocated with components.
 * - **Middleware**: You can pass an array of functions as the first argument to act as interruptors (e.g. for auth).
 *
 * @example
 * ```ts
 * // getters.ts
 * "use server"
 *
 * export const getUser = serverQuery(async (id: string) => {
 *   return db.user.findUnique({ where: { id } })
 * })
 * ```
 */
export declare function serverQuery<TArgs extends any[], TResult>(fnsOrFn: ServerFunction<TArgs, TResult> | [...Interruptor<TArgs>[], ServerFunction<TArgs, TResult>], options?: ServerFunctionOptions): WrappedServerFunction<TArgs, TResult>;
/**
 * Wrap a function to be used as a server action.
 *
 * - **Method**: Defaults to `POST`. can be changed via `options`.
 * - **Behavior**: When called from the client, it **will** rehydrate and re-render the React page with the new server state.
 * - **Location**: Must be defined in a file with `"use server"`. We recommend `actions.ts` colocated with components.
 * - **Middleware**: You can pass an array of functions as the first argument to act as interruptors (e.g. for auth).
 *
 * @example
 * ```ts
 * // actions.ts
 * "use server"
 *
 * export const updateUser = serverAction(async (id: string, data: any) => {
 *   return db.user.update({ where: { id }, data })
 * })
 * ```
 */
export declare function serverAction<TArgs extends any[], TResult>(fnsOrFn: ServerFunction<TArgs, TResult> | [...Interruptor<TArgs>[], ServerFunction<TArgs, TResult>], options?: ServerFunctionOptions): WrappedServerFunction<TArgs, TResult>;
export {};

export const middleware = `

# RedwoodSDK: Middleware

You're an expert at Cloudflare, TypeScript, and building web apps with RedwoodSDK. Generate high quality **RedwoodSDK middleware** that adhere to the following best practices:

## Guidelines

1. Create focused, single-responsibility middleware functions
2. Organize middleware in dedicated files (e.g., \`middleware.ts\`, \`middleware.tsx\`)
3. Use typed parameters and return values
4. Include clear error handling and logging
5. Follow the principle of least privilege
6. Implement proper security headers and CORS policies
7. Optimize for performance with caching strategies

## What is Middleware?

Middleware functions in RedwoodSDK are functions that run on every request before your route handlers. They can:

- Add security headers
- Handle CORS
- Implement caching strategies
- Add request/response logging
- Transform request/response data
- Implement rate limiting
- Add performance monitoring
- Handle error boundaries
- Setup sessions
- Authenticate users

## Example Templates

### Basic Middleware Structure

\`\`\`tsx
export default defineApp([
  setCommonHeaders(),
  async ({ ctx, request, response }) => {
    await setupDb(env);
    setupSessionStore(env);
    try {
      // Grab the session's data.
      ctx.session = await sessions.load(request);
    } catch (error) {
      if (error instanceof ErrorResponse && error.code === 401) {
        await sessions.remove(request, response.headers);
        response.headers.set("Location", "/user/login");

        return new Response(null, {
          status: 302,
          headers: response.headers,
        });
      }

      throw error;
    }

    // Populate the ctx with the user's data
    if (ctx.session?.userId) {
      ctx.user = await db.user.findUnique({
        where: {
          id: ctx.session.userId,
        },
      });
    }
  },
  // Route handlers
]);
\`\`\`
`;

export const interruptors = `

# RedwoodSDK: Request Interruptors

You're an expert at Cloudflare, TypeScript, and building web apps with RedwoodSDK. Generate high quality **RedwoodSDK interruptors** (middleware functions) that adhere to the following best practices:

## Guidelines

1. Create focused, single-responsibility interruptors
2. Organize interruptors in dedicated files (e.g., \`interruptors.ts\`, \`interceptors.ts\`, or \`middleware.ts\`)
3. Compose interruptors to create more complex validation chains
4. Use typed parameters and return values
5. Include clear error handling and user feedback

## What are Interruptors?

Interruptors are middleware functions that run before your route handlers. They can:

- Validate user authentication and authorization
- Transform request data
- Validate inputs
- Rate limit requests
- Log activity
- Redirect users based on conditions
- Short-circuit request handling with early responses

## Example Templates

### Basic Interruptor Structure

\`\`\`tsx
async function myInterruptor({ request, params, ctx }) {
  // Perform checks or transformations here

  // Return modified context to pass to the next interruptor or handler
  ctx.someAddedData = "value";

  // OR return a Response to short-circuit the request
  // return new Response('Unauthorized', { status: 401 });
}
\`\`\`

### Authentication Interruptors

\`\`\`tsx
export async function requireAuth({ request, ctx }) {
  if (!ctx.user) {
    return new Response(null, {
      status: 302,
      headers: { Location: "/user/login" },
    });
  }
}

export async function requireAdmin({ request, ctx }) {
  if (!ctx?.user?.isAdmin) {
    return new Response(null, {
      status: 302,
      headers: { Location: "/user/login" },
    });
  }
}
\`\`\`

### Input Validation Interruptor

\`\`\`tsx
import { z } from "zod";

// Create a reusable validator interruptor
export function validateInput(schema) {
  return async function validateInputInterruptor({ request, ctx }) {
    try {
      const data = await request.json();
      const validated = (ctx.data = schema.parse(data));
    } catch (error) {
      return Response.json(
        { error: "Validation failed", details: error.errors },
        { status: 400 },
      );
    }
  };
}

// Usage example with a Zod schema
const userSchema = z.object({
  name: z.string().min(2),
  email: z.string().email(),
  age: z.number().min(18).optional(),
});

export const validateUser = validateInput(userSchema);
\`\`\`

### Logging Interruptor

\`\`\`tsx
export async function logRequests({ request, ctx }) {
  const start = Date.now();

  // Add a function to the context that will log when called
  ctx.logCompletion: (response) => {
      const duration = Date.now() - start;
      const status = response.status;
      console.log(
        \`\${request.method} \${request.url} - \${status} (\${duration}ms)\`,
      );
    },
  };
}

// Usage in a route handler
route('/', [
  logRequests,
  async ({request, ctx}) => {
    // Call the logging function
    ctx.logCompletion(response);
    return Response.json({ success: true });;
  },
]);
\`\`\`

### Composing Multiple Interruptors

\`\`\`tsx
import { route } from "rwsdk/router";
import {
  requireAuth,
  validateUser,
  apiRateLimit,
  logRequests,
} from "@/app/interruptors";

// Combine multiple interruptors
route("/api/users", [
    logRequests, // Log all requests
    requireAuth, // Ensure user is authenticated
    validateUser, // Validate user input
    async ({ request, ctx }) => {
      // Handler receives validated data and session from interruptors
      const newUser = await db.user.create({
        data: {
          /* ... */,
          createdBy: ctx.user.userId,
        },
      });

      return Response.json(newUser, { status: 201 });
    },
  ],
});
\`\`\`

### Role-Based Access Control

\`\`\`tsx
import { getSession } from "rwsdk/auth";

// Create a function that generates role-based interruptors
export function hasRole(allowedRoles) {
  return async function hasRoleInterruptor({ request, ctx }) {
    const session = await getSession(request);

    if (!session) {
      return Response.redirect("/login");
    }

    if (!allowedRoles.includes(session.role)) {
      return Response.json({ error: "Unauthorized" }, { status: 403 });
    }

    return { ...ctx, session };
  };
}

// Create specific role-based interruptors
export const isAdmin = hasRole(["ADMIN"]);
export const isEditor = hasRole(["ADMIN", "EDITOR"]);
export const isUser = hasRole(["ADMIN", "EDITOR", "USER"]);
\`\`\`

### Organization with Co-located Interruptors

Create a file at \`./src/app/interruptors.ts\`:

\`\`\`tsx
import { getSession } from "rwsdk/auth";

// Authentication interruptors
export async function requireAuth({ request, ctx }) {
  const session = await getSession(request);

  if (!session) {
    return Response.redirect("/login");
  }

  return { ...ctx, session };
}

// Role-based interruptors
export function hasRole(allowedRoles) {
  return async function hasRoleInterruptor({ request, ctx }) {
    const session = await getSession(request);

    if (!session) {
      return Response.redirect("/login");
    }

    if (!allowedRoles.includes(session.role)) {
      return Response.json({ error: "Unauthorized" }, { status: 403 });
    }

    return { ...ctx, session };
  };
}

export const isAdmin = hasRole(["ADMIN"]);
export const isEditor = hasRole(["ADMIN", "EDITOR"]);

// Other common interruptors
export async function logRequests({ request, ctx }) {
  console.log(\`\${request.method} \${request.url}\`);
  return ctx;
}
\`\`\`

Then import these interruptors in your route files:

\`\`\`tsx
// src/app/pages/admin/routes.ts
import { route } from "rwsdk/router";
import { isAdmin, logRequests } from "@/app/interruptors";

import { AdminDashboard } from "./AdminDashboard";
import { UserManagement } from "./UserManagement";

export const routes = [
  route("/", [isAdmin, logRequests, AdminDashboard]),
  route("/users", [isAdmin, logRequests, UserManagement]),
];
\`\`\`

`;

export const requestResponse = `
# RedwoodSDK: Request handling and responses

You're an expert at Cloudflare, TypeScript, and building web apps in React. Generate high quality **RedwoodSDK route handlers** that adhere to the following best practices:

## Guidelines

1. Try to use Web APIs instead of external dependencies (e.g. use fetch instead of Axios, use WebSockets API instead of node-ws)
2. Co-locate related routes into a separate \`routes.ts\` file in \`./src/app/pages/<section>\` (e.g. keep all "user" routes in \`./src/app/pages/user/routes.ts\`, all "blog" routes in \`./src/app/pages/blog/routes.ts\`), and then import them into \`defineApp\` with the \`prefix\` function
4. Structure response data consistently with proper status codes
5. Handle errors gracefully and return appropriate error responses

## Example Templates

### Basic Routing

Routes are matched in the order they are defined. Define routes using the \`route\` function. Trailing slashes are optional and normalized internally.

#### Static Path Matching

\`\`\`tsx
// Match exact pathnames
route("/", function handler() {
  return <>Home Page</>
})

route("/about", function handler() {
  return <>About Page</>
})

route("/contact", function handler() {
  return <>Contact Page</>
})
\`\`\`

#### Dynamic Path Parameters

\`\`\`tsx
// Match dynamic segments marked with a colon (:)
route("/users/:id", function handler({ params }) {
  // params.id contains the value from the URL
  return <>User profile for {params.id}</>
})

route("/posts/:postId/comments/:commentId", function handler({ params }) {
  // Access multiple parameters
  return <>Comment {params.commentId} on Post {params.postId}</>
})
\`\`\`

#### Wildcard Path Matching

\`\`\`tsx
// Match all remaining segments after the prefix
route("/files/*", function handler({ params }) {
  // params.$0 contains the wildcard value
  return <>File: {params.$0}</>
})

route("/docs/*/version/*", function handler({ params }) {
  // Multiple wildcards available as params.$0, params.$1, etc.
  return <>Document: {params.$0}, Version: {params.$1}</>
})
\`\`\`

### Response Types

#### Plain Text Response

\`\`\`tsx
import { route } from "rwsdk/router";

route("/api/status", function handler() {
  return new Response("OK", {
    status: 200,
    headers: { "Content-Type": "text/plain" }
  })
})
\`\`\`

#### JSON Response

\`\`\`tsx
import { route } from "rwsdk/router";

route("/api/users/:id", function handler({ params }) {
  const userData = { id: params.id, name: "John Doe", email: "john@example.com" }

  return Response.json(userData, {
    status: 200,
    headers: {
      "Cache-Control": "max-age=60"
    }
  })
})
\`\`\`

#### JSX/React Components Response

\`\`\`tsx
import { route } from "rwsdk/router";
import { UserProfile } from '@/app/components/UserProfile'

route("/users/:id", function handler({ params }) {
  return <UserProfile userId={params.id} />
})
\`\`\`

#### Custom Document Template

\`\`\`tsx
import { render, route } from "rwsdk/router";
import { Document } from '@/app/Document'

render(Document, [
  route("/", function handler() {
    return <>Home Page</>
  }),
  route("/about", function handler() {
    return <>About Page</>
  })
])
\`\`\`

### Error Handling

\`\`\`tsx
import { route } from "rwsdk/router";

route("/api/posts/:id", async function handler({ params }) {
  try {
    const post = await db.post.findUnique({ where: { id: params.id } })

    if (!post) {
      return Response.json(
        { error: "Post not found" },
        { status: 404 }
      )
    }

    return Response.json(post)
  } catch (error) {
    console.error(error)
    return Response.json(
      { error: "Failed to retrieve post" },
      { status: 500 }
    )
  }
})
\`\`\`

### Organization with Co-located Routes

Create a file at \`./src/app/pages/blog/routes.ts\`:

\`\`\`tsx
import { route } from "rwsdk/router";
import { isAdminUser } from '@/app/interceptors'

import { BlogLandingPage } from './BlogLandingPage'
import { BlogPostPage } from './BlogPostPage'
import { BlogAdminPage } from './BlogAdminPage'

export const routes = [
  route('/', BlogLandingPage),
  route('/post/:postId', BlogPostPage),
  route('/post/:postId/edit', [isAdminUser, BlogAdminPage])
]
\`\`\`

Then import these routes in your main worker file:

\`\`\`tsx
// src/worker.tsx
import { defineApp, render, route, prefix } from "rwsdk/router";
import { Document } from '@/app/Document'
import { HomePage } from '@/app/pages/home/HomePage'
import { routes as blogRoutes } from '@/app/pages/blog/routes'

export default defineApp([
  /* middleware */
  render(Document, [
    route('/', HomePage),
    prefix('/blog', blogRoutes)
  ]),
])
\`\`\`

### Advanced: Route with Query Parameters

\`\`\`tsx
import { route } from "rwsdk/router";

route("/api/search", function handler({ request }) {
  const url = new URL(request.url)
  const query = url.searchParams.get('q') || ''
  const page = parseInt(url.searchParams.get('page') || '1')
  const limit = parseInt(url.searchParams.get('limit') || '10')

  return Response.json({
    query,
    page,
    limit,
    results: [] // Your search results would go here
  })
})
\`\`\`

`;

import { jsx as _jsx, jsxs as _jsxs } from "react/jsx-runtime";
import { normalizeActionResult } from "./render/normalizeActionResult";
import { renderDocumentHtmlStream } from "./render/renderDocumentHtmlStream";
import { renderToRscStream } from "./render/renderToRscStream";
import { injectRSCPayload } from "rsc-html-stream/server";
import { ErrorResponse } from "./error";
import { createRscActionHandler } from "./register/worker";
import { getRequestInfo, runWithRequestInfo, runWithRequestInfoOverrides, } from "./requestInfo/worker";
import { ssrWebpackRequire } from "./imports/worker";
import { defineRoutes } from "./lib/router";
import { generateNonce } from "./lib/utils";
export * from "./requestInfo/types";
export const defineApp = (routes, options = {}) => {
    const router = defineRoutes(routes);
    const rscActionHandler = createRscActionHandler({
        allowedOrigins: options.allowedOrigins,
    });
    return {
        __rwRoutes: routes,
        fetch: async (request, env, cf) => {
            globalThis.__webpack_require__ = ssrWebpackRequire;
            // context(justinvdm, 17 Mar 2026): Strip the Vite base path from the
            // request URL so that routes defined as "/" match requests to "/app/"
            // when base: '/app/' is configured. Vite injects BASE_URL automatically.
            const base = import.meta.env.BASE_URL;
            if (base && base !== "/") {
                const url = new URL(request.url);
                if (url.pathname.startsWith(base)) {
                    url.pathname = "/" + url.pathname.slice(base.length);
                    request = new Request(url.toString(), request);
                }
            }
            // context(justinvdm, 5 Feb 2025): Serve assets requests using the assets service binding
            // todo(justinvdm, 5 Feb 2025): Find a way to avoid this so asset requests are served directly
            // rather than first needing to go through the worker
            if (request.url.includes("/assets/")) {
                const url = new URL(request.url);
                url.pathname = url.pathname.slice("/assets/".length);
                return env.ASSETS.fetch(new Request(url.toString(), request));
            }
            else if (import.meta.env.VITE_IS_DEV_SERVER &&
                new URL(request.url).pathname === "/__worker-run") {
                const expectedToken = import.meta.env
                    .VITE_RWSDK_WORKER_RUN_TOKEN;
                const requestToken = request.headers.get("x-rwsdk-worker-run-token");
                if (!expectedToken || expectedToken !== requestToken) {
                    return new Response("Forbidden", { status: 403 });
                }
                const url = new URL(request.url);
                const scriptPath = url.searchParams.get("script");
                if (!scriptPath) {
                    return new Response("Missing 'script' query parameter", {
                        status: 400,
                    });
                }
                try {
                    const scriptModule = await import(/* @vite-ignore */ scriptPath);
                    if (scriptModule.default) {
                        await scriptModule.default(request, env, cf);
                    }
                    return new Response("Script executed successfully");
                }
                catch (e) {
                    console.error(`Error executing script: ${scriptPath}\n\n${e.stack}`);
                    return new Response(`Error executing script: ${e.message}`, {
                        status: 500,
                    });
                }
            }
            else if (import.meta.env.VITE_IS_DEV_SERVER &&
                request.url.includes("/__vite_preamble__")) {
                return new Response('import RefreshRuntime from "/@react-refresh"; RefreshRuntime.injectIntoGlobalHook(window); window.$RefreshReg$ = () => {}; window.$RefreshSig$ = () => (type) => type; window.__vite_plugin_react_preamble_installed__ = true;', {
                    headers: {
                        "content-type": "text/javascript",
                    },
                });
            }
            try {
                const url = new URL(request.url);
                let path = url.pathname;
                if (path !== "/" && !path.endsWith("/")) {
                    path = path + "/";
                }
                const isRSCRequest = url.searchParams.has("__rsc") ||
                    request.headers.get("accept")?.includes("text/x-component");
                const isAction = url.searchParams.has("__rsc_action_id");
                const rw = {
                    Document: DefaultDocument,
                    nonce: generateNonce(),
                    rscPayload: true,
                    ssr: true,
                    databases: new Map(),
                    scriptsToBeLoaded: new Set(),
                    entryScripts: new Set(),
                    inlineScripts: new Set(),
                    pageRouteResolved: undefined,
                };
                const userResponseInit = {
                    status: 200,
                    headers: new Headers(),
                };
                const outerRequestInfo = {
                    request,
                    path,
                    cf,
                    params: {},
                    ctx: {},
                    rw,
                    response: userResponseInit,
                    isAction,
                };
                const createPageElement = (requestInfo, Page) => {
                    let pageElement;
                    if (isClientReference(Page)) {
                        const { ctx, params } = requestInfo; // context(justinvdm, 25 Feb 2025): If the page is a client reference, we need to avoid passing
                        // down props the client shouldn't get (e.g. env). For safety, we pick the allowed props explicitly.
                        pageElement = _jsx(Page, { ctx: ctx, params: params });
                    }
                    else {
                        pageElement = _jsx(Page, { ...requestInfo });
                    }
                    return pageElement;
                };
                const renderPage = async (requestInfo, Page, _onError) => {
                    if (isClientReference(requestInfo.rw.Document)) {
                        if (import.meta.env.DEV) {
                            console.error("Document cannot be a client component");
                        }
                        return new Response(null, {
                            status: 500,
                        });
                    }
                    // context(justinvdm, 2026-03-17): Capture rendering errors so the
                    // router can throw them and route to except handlers. We store the
                    // error on rw.renderError instead of throwing from renderPage, because
                    // throwing mid-render corrupts React's internal RSC stream state
                    // (causing "chunk.reason.enqueueModel is not a function" in subsequent
                    // renders). By returning normally, streams are cleaned up properly.
                    const onError = (error) => {
                        if (!rw.renderError) {
                            rw.renderError = error;
                        }
                    };
                    const actionResult = normalizeActionResult(requestInfo.rw.actionResult);
                    const isDataOnly = request.headers.get("x-rsc-data-only") === "true";
                    const pageElement = isDataOnly && actionResult !== undefined
                        ? null
                        : createPageElement(requestInfo, Page);
                    if (pageElement === null) {
                        rw.pageRouteResolved?.resolve();
                    }
                    const { rscPayload: shouldInjectRSCPayload } = rw;
                    let rscPayloadStream = renderToRscStream({
                        input: {
                            node: pageElement,
                            actionResult,
                        },
                        onError,
                    });
                    if (isRSCRequest) {
                        const responseHeaders = new Headers(userResponseInit.headers);
                        responseHeaders.set("content-type", "text/x-component; charset=utf-8");
                        return new Response(rscPayloadStream, {
                            status: userResponseInit.status,
                            statusText: userResponseInit.statusText,
                            headers: responseHeaders,
                        });
                    }
                    let injectRSCPayloadStream;
                    if (shouldInjectRSCPayload) {
                        const [rscPayloadStream1, rscPayloadStream2] = rscPayloadStream.tee();
                        rscPayloadStream = rscPayloadStream1;
                        injectRSCPayloadStream = injectRSCPayload(rscPayloadStream2, {
                            nonce: rw.nonce,
                        });
                    }
                    let html;
                    try {
