import type { RequestInfo } from "rwsdk/worker";
import { parse } from "cookie";

const SAFE_METHODS = new Set(["GET", "HEAD", "OPTIONS"]);

/**
 * Constant-time string comparison to prevent timing attacks.
 * Returns true if the strings are equal, false otherwise.
 */
function timingSafeEqual(a: string, b: string): boolean {
  if (a.length !== b.length) {
    return false;
  }
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

/**
 * Extract the csrf cookie value from a Request's Cookie header.
 */
function getCsrfCookieValue(request: Request): string | undefined {
  const cookieHeader = request.headers.get("Cookie");
  if (!cookieHeader) return undefined;
  const cookies = parse(cookieHeader);
  return cookies["csrf"];
}

/**
 * Parse a URL-encoded form body and extract the _csrf field.
 */
async function getCsrfFromFormBody(request: Request): Promise<string | undefined> {
  const contentType = request.headers.get("Content-Type") || "";
  if (!contentType.includes("application/x-www-form-urlencoded")) {
    return undefined;
  }
  // Clone the request so we don't consume the original body
  const cloned = request.clone();
  const text = await cloned.text();
  const params = new URLSearchParams(text);
  return params.get("_csrf") ?? undefined;
}

/**
 * Global middleware that enforces CSRF protection for unsafe HTTP methods.
 * Safe methods (GET, HEAD, OPTIONS) are always allowed through.
 * For unsafe methods (POST, PUT, DELETE, PATCH), the request must include
 * a csrf cookie and either an X-CSRF-Token header or a _csrf form field
 * that matches the cookie value.
 */
export async function csrfGuard({ request }: RequestInfo): Promise<Response | void> {
  const method = request.method.toUpperCase();

  // Safe methods are always allowed
  if (SAFE_METHODS.has(method)) {
    return;
  }

  const cookieValue = getCsrfCookieValue(request);

  // Check X-CSRF-Token header first
  const headerValue = request.headers.get("X-CSRF-Token");

  if (headerValue !== null && cookieValue !== undefined) {
    if (timingSafeEqual(headerValue, cookieValue)) {
      return; // CSRF token matches, allow through
    }
  }

  // If header is not present or doesn't match, try form body _csrf field
  if (!headerValue) {
    const formValue = await getCsrfFromFormBody(request);
    if (formValue !== undefined && cookieValue !== undefined) {
      if (timingSafeEqual(formValue, cookieValue)) {
        return; // CSRF token matches, allow through
      }
    }
  }

  // CSRF validation failed
  return new Response(JSON.stringify({ error: "invalid_csrf_token" }), {
    status: 403,
    headers: { "Content-Type": "application/json" },
  });
}

/**
 * GET /csrf - Issues a fresh CSRF token.
 * Sets a cookie named "csrf" with SameSite=Strict and Path=/.
 * Returns JSON: {"token": "<32 hex chars>"}
 */
export function handleCsrfToken(): Response {
  const token = generateCsrfToken();
  const body = JSON.stringify({ token });

  return new Response(body, {
    status: 200,
    headers: {
      "Content-Type": "application/json",
      "Set-Cookie": `csrf=${token}; SameSite=Strict; Path=/`,
    },
  });
}

/**
 * Generate a 32-character hex CSRF token from 16 random bytes.
 */
function generateCsrfToken(): string {
  const bytes = crypto.getRandomValues(new Uint8Array(16));
  return Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

/**
 * GET /api/health - Health check endpoint.
 * Always reachable, no CSRF protection needed (safe method).
 */
export function handleHealth(): Response {
  return new Response(JSON.stringify({ status: "ok" }), {
    status: 200,
    headers: { "Content-Type": "application/json" },
  });
}

/**
 * Comments storage (in-memory, per-process).
 */
interface Comment {
  id: number;
  author: string;
  text: string;
}

const comments: Comment[] = [];
let nextId = 1;

/**
 * Handle /api/comments with method-based routing:
 * - GET: list all comments (public, no CSRF needed)
 * - POST: create a comment (CSRF-protected by global middleware)
 */
export const handleComments = {
  get: listComments,
  post: createComment,
};

/**
 * GET /api/comments - List all comments.
 */
function listComments(): Response {
  return new Response(JSON.stringify(comments), {
    status: 200,
    headers: { "Content-Type": "application/json" },
  });
}

/**
 * POST /api/comments - Create a new comment.
 * CSRF protection is handled by the global middleware before this handler runs.
 * This handler assumes the request has been validated.
 * Supports both JSON and form-urlencoded content types.
 */
async function createComment({ request }: { request: Request }): Promise<Response> {
  const contentType = request.headers.get("Content-Type") || "";
  let author: string | undefined;
  let text: string | undefined;

  if (contentType.includes("application/json")) {
    const body = await request.json();
    author = (body as Record<string, unknown>).author as string;
    text = (body as Record<string, unknown>).text as string;
  } else if (contentType.includes("application/x-www-form-urlencoded")) {
    const body = await request.text();
    const params = new URLSearchParams(body);
    author = params.get("author") ?? undefined;
    text = params.get("text") ?? undefined;
  } else {
    return new Response(JSON.stringify({ error: "unsupported_content_type" }), {
      status: 415,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (!author || !text) {
    return new Response(JSON.stringify({ error: "missing_fields" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  const comment: Comment = {
    id: nextId++,
    author,
    text,
  };

  comments.push(comment);

  return new Response(JSON.stringify(comment), {
    status: 201,
    headers: { "Content-Type": "application/json" },
  });
}

